      d="M8.709 12.416a1.6 1.6 0 0 1-.725-.159 1.14 1.14 0 0 1-.475-.45 1.36 1.36 0 0 1-.168-.687l-.005-.749h.998v.744q0 .169.063.283.062.12.182.183.12.062.283.062h.788v.773zm-.864-2.376q.643 0 1.166-.322.524-.326.816-.897.298-.576.298-1.301 0-.73-.293-1.3A2.16 2.16 0 0 0 7.845 5q-.652 0-1.176.326a2.25 2.25 0 0 0-.816.893q-.298.57-.298 1.3t.298 1.302.816.897a2.2 2.2 0 0 0 1.176.322m0 .955a3.3 3.3 0 0 1-1.714-.451 3.3 3.3 0 0 1-1.21-1.248A3.6 3.6 0 0 1 4.48 7.52q0-.98.442-1.771a3.293 3.293 0 0 1 2.923-1.704q.936 0 1.704.456.772.45 1.21 1.248.441.792.441 1.77 0 .98-.442 1.777a3.24 3.24 0 0 1-1.21 1.248q-.768.45-1.703.451"
      fill="#208A3C"
    />
  </svg>
);

const QueryDark: React.FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title && <title>{title}</title>}
    <rect
      x="2.5"
      y="2.5"
      width="11"
      height="11"
      rx="1.5"
      fill="#253627"
      stroke="#57965C"
    />
    <path
      d="M8.709 12.416a1.6 1.6 0 0 1-.725-.159 1.14 1.14 0 0 1-.475-.45 1.36 1.36 0 0 1-.168-.687l-.005-.749h.998v.744q0 .169.063.283.062.12.182.183.12.062.283.062h.788v.773zm-.864-2.376q.643 0 1.166-.322.524-.326.816-.897.298-.576.298-1.301 0-.73-.293-1.3A2.16 2.16 0 0 0 7.845 5q-.652 0-1.176.326a2.25 2.25 0 0 0-.816.893q-.298.57-.298 1.3t.298 1.302.816.897a2.2 2.2 0 0 0 1.176.322m0 .955a3.3 3.3 0 0 1-1.714-.451 3.3 3.3 0 0 1-1.21-1.248A3.6 3.6 0 0 1 4.48 7.52q0-.98.442-1.771a3.293 3.293 0 0 1 2.923-1.704q.936 0 1.704.456.772.45 1.21 1.248.441.792.441 1.77 0 .98-.442 1.777a3.24 3.24 0 0 1-1.21 1.248q-.768.45-1.703.451"
      fill="#57965C"
    />
  </svg>
);

export const Query: React.FC<QueryProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? QueryLight : QueryDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
